(248,	43,	'_elementor_data',	'[{\"id\":\"43b93d7\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"79b6375\",\"elType\":\"widget\",\"settings\":{\"classes\":{\"$$type\":\"classes\",\"value\":[\"e-79b6375-e009d07\"]},\"tag\":{\"$$type\":\"string\",\"value\":\"h3\"},\"title\":{\"$$type\":\"html-v3\",\"value\":{\"content\":{\"$$type\":\"string\",\"value\":\"Grafikon 1 \\u2013 Struktura digitalnih vje\\u0161tina u BiH (2024)\"},\"children\":[]}},\"link\":{\"$$type\":\"link\",\"value\":{\"isTargetBlank\":null}}},\"elements\":[],\"widgetType\":\"e-heading\",\"styles\":{\"e-79b6375-e009d07\":{\"id\":\"e-79b6375-e009d07\",\"label\":\"local\",\"type\":\"class\",\"variants\":[{\"meta\":{\"breakpoint\":\"desktop\",\"state\":null},\"props\":{\"align-self\":{\"$$type\":\"string\",\"value\":\"center\"}},\"custom_css\":null}]}},\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"},{\"id\":\"d7e7005\",\"elType\":\"widget\",\"settings\":{\"shortcode\":\"[visualizer id=\\\"34\\\" class=\\\"\\\"]\"},\"elements\":[],\"widgetType\":\"shortcode\"},{\"id\":\"0ecb58b\",\"elType\":\"widget\",\"settings\":{\"paragraph\":{\"$$type\":\"html-v3\",\"value\":{\"content\":{\"$$type\":\"string\",\"value\":\"Kru\\u017eni dijagram jasno ilustruje kriti\\u010dno stanje digitalne pismenosti u Bosni i Hercegovini. \\u010cak 56% odraslog stanovni\\u0161tva ulazi u kategoriju bez ikakvih formalnih digitalnih vje\\u0161tina. To zna\\u010di da vi\\u0161e od polovine radne snage ne ispunjava osnovne preduslove modernog tr\\u017ei\\u0161ta rada. S druge strane, svega 13% gra\\u0111ana posjeduje napredne vje\\u0161tine (iznad osnovnog nivoa), \\u0161to direktno limitira razvoj doma\\u0107e digitalne ekonomije i privla\\u010denje stranih investicija.\"},\"children\":[]}},\"link\":{\"$$type\":\"link\",\"value\":{\"isTargetBlank\":null}}},\"elements\":[],\"widgetType\":\"e-paragraph\",\"styles\":[],\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"}],\"isInner\":false}]'),
