(630,	80,	'_elementor_data',	'[{\"id\":\"c8f65e4\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"7dce3ee\",\"elType\":\"widget\",\"settings\":{\"title\":\"Digitalna pismenost i zaposlenost u informacionom dru\\u0161tvu\",\"align\":\"center\"},\"elements\":[],\"widgetType\":\"heading\"}],\"isInner\":false},{\"id\":\"df6ab88\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"7aa615e\",\"elType\":\"widget\",\"settings\":[],\"elements\":[],\"widgetType\":\"spacer\"},{\"id\":\"e347507\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>Dobrodo\\u0161li na platformu posve\\u0107enu istra\\u017eivanju uticaja digitalne pismenosti na savremeno tr\\u017ei\\u0161te rada. Ovaj rad analizira klju\\u010dne statisti\\u010dke podatke o nivou digitalnih kompetencija u Bosni i Hercegovini i Evropskoj uniji, trendove rasta u IKT sektoru, kao i direktnu korelaciju izme\\u0111u tehnolo\\u0161kih znanja i stope zaposlenosti. Kroz interaktivne tabele, grafikone i ankete, sajt pru\\u017ea jasan uvid u izazove i \\u0161anse koje digitalna transformacija donosi pojedincima i dru\\u0161tvu.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]'),
