(1764,	156,	'_elementor_data',	'[{\"id\":\"27fa4d3\",\"elType\":\"container\",\"settings\":[],\"elements\":[{\"id\":\"5a20429\",\"elType\":\"widget\",\"settings\":{\"paragraph\":{\"$$type\":\"html-v3\",\"value\":{\"content\":{\"$$type\":\"string\",\"value\":\"Prema podacima Eurostat-a za 2024. godinu, uo\\u010dava se zna\\u010dajan digitalni jaz izme\\u0111u zemalja Evropske unije i regiona Balkana. Dok napredne ekonomije poput Finske bilje\\u017ee minimalan procenat stanovni\\u0161tva bez digitalnih kompetencija, Bosna i Hercegovina se suo\\u010dava sa ozbiljnim strukturnim izazovom gde vi\\u0161e od polovine stanovni\\u0161tva nema formalnu digitalnu pismenost.\"},\"children\":[]}},\"link\":{\"$$type\":\"link\",\"value\":{\"isTargetBlank\":null}}},\"elements\":[],\"widgetType\":\"e-paragraph\",\"styles\":[],\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"},{\"id\":\"b192706\",\"elType\":\"widget\",\"settings\":{\"shortcode\":\"[wpdatatable id=1]\"},\"elements\":[],\"widgetType\":\"shortcode\"}],\"isInner\":false},{\"id\":\"dd2e49f\",\"elType\":\"e-flexbox\",\"settings\":[],\"elements\":[{\"id\":\"658fa44\",\"elType\":\"widget\",\"settings\":{\"paragraph\":{\"$$type\":\"html-v3\",\"value\":{\"content\":{\"$$type\":\"string\",\"value\":\"Iz Tabele 1 jasno je vidljiv geografski obrazac digitalnog jaza u Evropi: \\u0161to se kre\\u0107emo prema jugoistoku, to su pokazatelji slabiji. Posebno zabrinjava podatak da u BiH \\u010dak 56% odrasle radne snage nema digitalne vje\\u0161tine. U praksi to zna\\u010di da vi\\u0161e od polovine radno sposobnog stanovni\\u0161tva nije u stanju da se prijavi za posao putem online platformi ili koristi osnovne softverske alate. <em>Napomena: Podaci za Finsku i EU prosjek prikazuju kumulativni procenat gra\\u0111ana sa najmanje osnovnim vje\\u0161tinama, dok su za ostale zemlje prikazane striktno razdvojene kategorije (zbir daje 100%).<\\/em>*\"},\"children\":[]}},\"link\":{\"$$type\":\"link\",\"value\":{\"isTargetBlank\":null}}},\"elements\":[],\"widgetType\":\"e-paragraph\",\"styles\":[],\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"}],\"isInner\":false,\"styles\":[],\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"}]'),
